import Chart from "chart.js/auto";

export const DEFAULT_CONFIG_CHART: ChartConfiguration<'doughnut'>['options'] = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: {
      display: true,
      position: 'bottom'
    }
  }
};

export function getConfigChart(overrides?: ChartConfiguration<'doughnut'>['options']): ChartConfiguration<'doughnut'>['options'] {
  return {
    ...DEFAULT_CONFIG_CHART,
    ...overrides,
    plugins: {
      ...DEFAULT_CONFIG_CHART?.plugins,
      ...overrides?.plugins
    }
  };
}
