import {ChartOptions} from "chart.js";

export class ChartOptionsUtils {
  public static stackBarChartOptions: ChartOptions = {
    plugins: {
      legend: {
        title: {
          display: false,
          text: ""
        }
      },
      tooltip: {
        mode: 'index',
        intersect: false
      },
    },
    responsive: true,
    maintainAspectRatio: true,
    scales: {
      x: {
        stacked: true,
      },
      y: {
        beginAtZero: true,
        stacked: true,
        ticks: {
          display: true,
          autoSkip: false,
          callback(value: string | number, index: number): number | undefined {
            if (Number.isSafeInteger(value)) {
              return Number.parseInt(value.toString(), 0);
            }
            return undefined;
          }
        }
      }
    }
  };
  public static barChartOptions: ChartOptions = {
    plugins: {
      legend: {
        title: {
          display: false,
          text: ""
        }
      },
      tooltip: {
        mode: 'index',
        intersect: false
      },
    },
    responsive: true,
    maintainAspectRatio: true,
    scales: {
      x: {
        stacked: false,
      },
      y: {
        beginAtZero: true,
        stacked: false,
        ticks: {
          display: true,
          autoSkip: false,
          callback(value: string | number, index: number): number | undefined {
            if (Number.isSafeInteger(value)) {
              return Number.parseInt(value.toString(), 0);
            }
            return undefined;
          }
        }
      }
    }
  };

  public static funnelOptions = {
    responsive: true,
    sort: 'desc',
    legend: {
      position: 'top'
    },
    title: {
      display: false,
      text: ''
    },
    animation: {
      animateScale: true,
      animateRotate: true
    },
    tooltips: {
      callbacks: {
        title: function (tooltipItem: any, data: any) {
          return '';
        },
        label: function (tooltipItem: any, data: any) {
          return data.labels[tooltipItem.index] + ': ' + data.datasets[tooltipItem.datasetIndex].data[tooltipItem.index];
        }
      }
    }
  };
  public static chartBarLineOptions: ChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    interaction: {
      mode: 'index',
      intersect: false
    },
    plugins: {
      title: {
        display: false,
        text: "",
      },
      legend: {
        display: true,
        position: 'bottom',
      },
      tooltip: {
        callbacks: {
          label: (context: any) => {
            let label = context.dataset.label || '';
            if (label) {
              label += ': ';
            }
            if (context.parsed.y !== null) {
              label += new Intl.NumberFormat('vi-VN').format(context.parsed.y);
            }
            return label;
          }
        }
      }
    },
    scales: {
      y: {
        type: 'linear',
        display: true,
        position: 'left',
        title: {
          display: false,
          text: 'Bar Values'
        },
        grid: {
          drawOnChartArea: true
        }
      },
      y1: {
        type: 'linear',
        display: true,
        position: 'right',
        title: {
          display: false,
          text: 'Line Values'
        },
        grid: {
          drawOnChartArea: false
        }
      }
    }
  }
  public static lineCharOptions: ChartOptions ={
    responsive: true,
    maintainAspectRatio: false,
    interaction: {
      mode: 'index',
      intersect: false
    },
    plugins: {
      title: {
        display: false,
        text: "",
        align: 'start',
        font: {
          size: 16,
          weight: 'bold'
        }
      },
      legend: {
        display: true,
        position: 'bottom'
      },
      tooltip: {
        callbacks: {
          label: (context) => {
            let label = context.dataset.label || '';
            if (label) {
              label += ': ';
            }
            if (context.parsed.y !== null) {
              label += new Intl.NumberFormat('vi-VN').format(context.parsed.y);
            }
            return label;
          }
        }
      }
    },
    scales: {
      x: {
        offset: true,
        grid: {
          offset: true
        }
      },
    }
  }
}
